    if not date_str:
        return None
    str_date = str(date_str).lower()
    months = ['jan', 'feb', 'mar', 'apr', 'may', 'jun', 'jul', 'aug', 'sep', 'oct', 'nov', 'dec']
    for i, month in enumerate(months, 1):
        if month in str_date:
            return i
    return None

